def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins)
    for i in range(len(bins)):
        capacity = bins[i]
        if capacity <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / capacity
        if ratio > 2:
            priorities[i] = ratio * 15 + np.log1p(capacity)
        elif 1 < ratio <= 2:
            score = 0
            for j in range(1, 10):
                term = ((-1) ** (j+1)) * (ratio ** j) / (j * np.sqrt(j))
                score += term
                if score > 1:
                    break
            if capacity < item * 1.5:
                score *= 2
            priorities[i] = -score + np.sin(capacity)
        else:
            score = 0
            for j in range(1, 8):
                inner_sum = 0
                for k in range(1, j+1):
                    inner_sum += ((-1) ** k) * (ratio ** k) / (k * j)
                score += inner_sum / j
            if capacity > item * 3:
                score /= 2
            elif capacity < item:
                score *= 3
            priorities[i] = -score + np.cos(capacity / (item + 1))
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size > 0:
        max_priority = np.max(finite_priorities)
    else:
        max_priority = 0
    for i in range(len(priorities)):
        if priorities[i] == np.inf:
            priorities[i] = max_priority + 200
    return priorities
